// Inter latin-subset woff2 fonts embedded as base64 — ensures text renders on Lambda (no system fonts).
// Source: @fontsource/inter@5.0.18 inter-latin-{400,700}-normal.woff2
export const INTER_400 = '';
export const INTER_700 = '';

export function fontStyle() {
  return `<defs><style>
@font-face{font-family:'Inter';font-weight:400;src:url('data:font/woff2;base64,${INTER_400}') format('woff2')}
@font-face{font-family:'Inter';font-weight:700;src:url('data:font/woff2;base64,${INTER_700}') format('woff2')}
@font-face{font-family:'Inter';font-weight:900;src:url('data:font/woff2;base64,${INTER_700}') format('woff2')}
</style></defs>`;
}
